# SnapTap Nginx Configuration
# Deployed automatically by Azure DevOps pipeline
# Last updated: See git history

server {
    server_name snaptap.co.za www.snaptap.co.za app.snaptap.co.za cards.snaptap.co.za card.snaptap.co.za menu.snaptap.co.za;

    listen 443 ssl;
    ssl_certificate /etc/letsencrypt/live/snaptap.co.za/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/snaptap.co.za/privkey.pem;
    include /etc/letsencrypt/options-ssl-nginx.conf;
    ssl_dhparam /etc/letsencrypt/ssl-dhparams.pem;

    # Security headers
    add_header X-Frame-Options "SAMEORIGIN" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header X-XSS-Protection "1; mode=block" always;

    # Gzip compression
    gzip on;
    gzip_vary on;
    gzip_min_length 1024;
    gzip_proxied any;
    gzip_types text/plain text/css text/xml text/javascript application/javascript application/json application/xml;

    # ==========================================
    # NUXT APP ROUTES (proxied to Node.js)
    # ==========================================

    # Nuxt build assets (_nuxt folder)
    location ^~ /_nuxt/ {
        proxy_pass http://127.0.0.1:3001;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;

        # Cache static assets
        expires 1y;
        add_header Cache-Control "public, immutable";
    }

    # Profile assets (JS engine, templates) - served by Nuxt
    location ^~ /profile-assets/ {
        proxy_pass http://127.0.0.1:3001;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;

        # Cache for 24 hours
        expires 24h;
        add_header Cache-Control "public";
    }

    # Fonts - served by Nuxt
    location ^~ /fonts/ {
        proxy_pass http://127.0.0.1:3001;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;

        # Cache fonts for a long time
        expires 1y;
        add_header Cache-Control "public, immutable";
    }

    # Static file assets (images, icons, etc.) - served by Nuxt
    location ~* ^/[^/]+\.(svg|png|jpg|jpeg|gif|ico|webp|avif|woff|woff2|ttf|eot|css|js|json|webmanifest)$ {
        proxy_pass http://127.0.0.1:3001;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;

        # Cache static assets
        expires 7d;
        add_header Cache-Control "public";
    }

    # Known Nuxt frontend routes - proxy to Node.js
    location ~ ^/(login|register|dashboard|profile|settings|admin|logout|about|contact|pricing|features|organizations|catalogs|search|help|verify-email|verify-sent|terms|privacy|categories)(/.*)?$ {
        proxy_pass http://127.0.0.1:3001;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;
    }

    # ==========================================
    # API ROUTES (proxied to ASP.NET backend)
    # ==========================================

    location ^~ /api/ {
        proxy_pass http://127.0.0.1:5000;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_read_timeout 60s;
        proxy_connect_timeout 60s;
    }

    # ==========================================
    # HOME PAGE
    # ==========================================

    # Root path - serve Nuxt home page
    location = / {
        proxy_pass http://127.0.0.1:3001;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;
    }

    # ==========================================
    # PROFILE SLUGS (static HTML from disk)
    # ==========================================

    # Everything else is a profile slug - serve from persistent profiles directory
    location / {
        proxy_pass http://127.0.0.1:3001;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;
    }

    # Fallback to Nuxt for dynamic routes or 404 handling
    location @nuxt_fallback {
        proxy_pass http://127.0.0.1:3001;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;
    }
}

# ==========================================
# HTTP to HTTPS redirect
# ==========================================

server {
    listen 80;
    server_name snaptap.co.za www.snaptap.co.za;
    return 301 https://snaptap.co.za$request_uri;
}

